   528→### 7.2 Screen Reader Support
   529→
   530→```typescript
   531→// Announce zoom level changes
   532→function announceZoom(zoom: number) {
   533→  const announcement = document.createElement('div');
   534→  announcement.setAttribute('role', 'status');
   535→  announcement.setAttribute('aria-live', 'polite');
   536→  announcement.textContent = `Zoom level: ${Math.round(zoom * 100)}%`;
   537→  document.body.appendChild(announcement);
   538→  setTimeout(() => announcement.remove(), 1000);
   539→}
