   551→
   552→### 7.3 Reduced Motion Preference
   553→
   554→```typescript
   555→const prefersReducedMotion = window.matchMedia(
   556→  '(prefers-reduced-motion: reduce)'
   557→).matches;
   558→
   559→function getAnimationDuration(defaultDuration: number): number {
   560→  return prefersReducedMotion ? 0 : defaultDuration;
   561→}
   562→```
