/**
 * StrategicLayer Component
 *
 * Displays a 12-year heatmap overview of maintenance workload.
 * Each cell represents a train-quarter combination, colored by man-hours.
 *
 * LOD: Strategic (<0.3x zoom)
 */

import React, { useMemo } from 'react';
import DeckGL from '@deck.gl/react';
import { OrthographicView } from '@deck.gl/core';
import { SolidPolygonLayer } from '@deck.gl/layers';
import type { PickingInfo } from '@deck.gl/core';
import type { AggregatedCell, Train } from '../../data/mock-generator';
import { COLORS, TIME_RANGE } from '../../data/mock-config';

// =============================================================================
// TYPES
// =============================================================================

export interface StrategicLayerProps {
  /** Aggregated cell data (by quarter) */
  cells: AggregatedCell[];
  /** Train data for labels */
  trains: Train[];
  /** Width of the viewport */
  width: number;
  /** Height of the viewport */
  height: number;
  /** Camera X position (pan) */
  cameraX?: number;
  /** Camera Y position (pan) */
  cameraY?: number;
  /** Zoom level */
  zoom?: number;
  /** Opacity for crossfade transitions */
  opacity?: number;
  /** Callback when a cell is clicked */
  onCellClick?: (cell: AggregatedCell) => void;
  /** Callback when a cell is hovered */
  onCellHover?: (cell: AggregatedCell | null) => void;
  /** Currently hovered cell */
  hoveredCell?: AggregatedCell | null;
  /** Show labels on cells */
  showLabels?: boolean;
}

interface CellPolygon {
  polygon: [number, number][];
  cell: AggregatedCell;
  color: [number, number, number, number];
}

// =============================================================================
// CONSTANTS
// =============================================================================

const CELL_WIDTH = 30; // pixels per quarter
const CELL_HEIGHT = 20; // pixels per train
const CELL_GAP = 1;

// Color ramp for heatmap (man-hours)
const COLOR_RAMP = [
  { threshold: 0, color: [248, 250, 252, 255] as [number, number, number, number] },    // slate-50 (no work)
  { threshold: 100, color: [254, 243, 199, 255] as [number, number, number, number] },  // amber-100
  { threshold: 500, color: [253, 224, 71, 255] as [number, number, number, number] },   // yellow-300
  { threshold: 1000, color: [251, 146, 60, 255] as [number, number, number, number] },  // orange-400
  { threshold: 2000, color: [239, 68, 68, 255] as [number, number, number, number] },   // red-500
  { threshold: 4000, color: [153, 27, 27, 255] as [number, number, number, number] },   // red-900
];

// Overhaul marker color
const OVERHAUL_COLOR: [number, number, number, number] = [147, 51, 234, 255]; // purple-600

// =============================================================================
// HELPERS
// =============================================================================

function getColorForManHours(manHours: number, hasOverhaul: boolean): [number, number, number, number] {
  if (hasOverhaul) {
    return OVERHAUL_COLOR;
  }

  for (let i = COLOR_RAMP.length - 1; i >= 0; i--) {
    if (manHours >= COLOR_RAMP[i].threshold) {
      return COLOR_RAMP[i].color;
    }
  }
  return COLOR_RAMP[0].color;
}

function createCellPolygons(cells: AggregatedCell[]): CellPolygon[] {
  return cells.map((cell) => {
    const x = cell.periodIndex * CELL_WIDTH;
    const y = cell.trainIndex * CELL_HEIGHT;
    const w = CELL_WIDTH - CELL_GAP;
    const h = CELL_HEIGHT - CELL_GAP;

    return {
      polygon: [
        [x, y],
        [x + w, y],
        [x + w, y + h],
        [x, y + h],
      ],
      cell,
      color: getColorForManHours(cell.totalManHours, cell.hasOverhaul),
    };
  });
}

// =============================================================================
// COMPONENT
// =============================================================================

export const StrategicLayer: React.FC<StrategicLayerProps> = ({
  cells,
  trains,
  width,
  height,
  cameraX = 0,
  cameraY = 0,
  zoom = 1,
  opacity = 1,
  onCellClick,
  onCellHover,
  hoveredCell,
  showLabels = false,
}) => {
  // Calculate total dimensions
  const totalWidth = TIME_RANGE.quarters * CELL_WIDTH;
  const totalHeight = trains.length * CELL_HEIGHT;

  // Create cell polygons
  const cellPolygons = useMemo(() => createCellPolygons(cells), [cells]);

  // Create deck.gl layers
  const layers = useMemo(() => {
    return [
      new SolidPolygonLayer<CellPolygon>({
        id: 'strategic-heatmap',
        data: cellPolygons,
        getPolygon: (d) => d.polygon,
        getFillColor: (d) => {
          // Highlight hovered cell
          if (hoveredCell &&
              d.cell.trainIndex === hoveredCell.trainIndex &&
              d.cell.periodIndex === hoveredCell.periodIndex) {
            return [255, 255, 255, 200] as [number, number, number, number];
          }
          return d.color;
        },
        pickable: true,
        opacity,
        updateTriggers: {
          getFillColor: [hoveredCell],
        },
      }),
    ];
  }, [cellPolygons, hoveredCell, opacity]);

  // Handle picking
  const handleClick = (info: PickingInfo) => {
    if (info.object && onCellClick) {
      onCellClick((info.object as CellPolygon).cell);
    }
  };

  const handleHover = (info: PickingInfo) => {
    if (onCellHover) {
      if (info.object) {
        onCellHover((info.object as CellPolygon).cell);
      } else {
        onCellHover(null);
      }
    }
  };

  // Create orthographic view
  const views = new OrthographicView({
    id: 'strategic-view',
    flipY: false,
    controller: false,
  });

  const viewState = {
    target: [totalWidth / 2 - cameraX, totalHeight / 2 - cameraY, 0],
    zoom: Math.log2(zoom),
  };

  return (
    <div style={{ width, height, position: 'relative' }}>
      <DeckGL
        width={width}
        height={height}
        views={views}
        viewState={viewState}
        layers={layers}
        onClick={handleClick}
        onHover={handleHover}
        getCursor={() => 'pointer'}
      />

      {/* Legend */}
      <div
        style={{
          position: 'absolute',
          bottom: 16,
          right: 16,
          background: 'white',
          padding: '8px 12px',
          borderRadius: 8,
          boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
          fontSize: 11,
          opacity,
        }}
      >
        <div style={{ fontWeight: 600, marginBottom: 4 }}>Man-Hours / Quarter</div>
        <div style={{ display: 'flex', gap: 4, alignItems: 'center' }}>
          {COLOR_RAMP.slice(1).map((c, i) => (
            <div
              key={i}
              style={{
                width: 20,
                height: 12,
                backgroundColor: `rgba(${c.color.join(',')})`,
                borderRadius: 2,
              }}
              title={`${c.threshold}+ hrs`}
            />
          ))}
        </div>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 2, color: '#666' }}>
          <span>0</span>
          <span>4000+</span>
        </div>
        <div style={{ marginTop: 4, display: 'flex', alignItems: 'center', gap: 4 }}>
          <div
            style={{
              width: 12,
              height: 12,
              backgroundColor: `rgba(${OVERHAUL_COLOR.join(',')})`,
              borderRadius: 2,
            }}
          />
          <span>Overhaul</span>
        </div>
      </div>

      {/* Hover tooltip */}
      {hoveredCell && (
        <div
          style={{
            position: 'absolute',
            top: 16,
            left: 16,
            background: 'white',
            padding: '8px 12px',
            borderRadius: 8,
            boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
            fontSize: 12,
            opacity,
          }}
        >
          <div style={{ fontWeight: 600 }}>
            {trains[hoveredCell.trainIndex]?.name ?? `Train ${hoveredCell.trainIndex}`}
          </div>
          <div style={{ color: '#666', marginTop: 2 }}>
            Q{(hoveredCell.periodIndex % 4) + 1} {2024 + Math.floor(hoveredCell.periodIndex / 4)}
          </div>
          <div style={{ marginTop: 4 }}>
            <span style={{ fontWeight: 500 }}>{hoveredCell.totalTasks}</span> tasks
          </div>
          <div>
            <span style={{ fontWeight: 500 }}>{hoveredCell.totalManHours.toLocaleString()}</span> man-hours
          </div>
          <div>
            <span style={{ fontWeight: 500 }}>{(hoveredCell.totalCostAed / 1000).toFixed(0)}K</span> AED
          </div>
          {hoveredCell.hasOverhaul && (
            <div style={{ color: '#9333ea', fontWeight: 500, marginTop: 2 }}>
              Includes Overhaul
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default StrategicLayer;

