     1→/**
     2→ * POC: Semantic Zoom with Crossfade Transitions
     3→ *
     4→ * Demonstrates smooth LOD transitions using opacity crossfade:
     5→ * - Strategic (zoom < 0.3): Heatmap overview
     6→ * - Tactical (0.3 <= zoom < 1.0): Stacked bars
     7→ * - Operational (1.0 <= zoom < 3.0): DNA Gantt pattern
     8→ * - Execution (zoom >= 3.0): Detailed task cards
     9→ *
    10→ * Key concepts:
    11→ * 1. Each LOD layer renders independently
    12→ * 2. Crossfade opacity based on zoom proximity to threshold
    13→ * 3. Smooth 60fps transitions without jarring changes
    14→ */
    15→
    16→import React, { useState, useMemo, useCallback, useRef, useEffect } from 'react';
    17→import type { Meta, StoryObj } from '@storybook/react';
    18→import { useGesture } from '@use-gesture/react';
    19→import { Card, Tag, Intent, Divider, ProgressBar, Slider } from '@blueprintjs/core';
    20→
    21→import { COLORS, LOD_THRESHOLDS, ANIMATION, getLODLevel } from '../../data/mock-config';
    22→import type { LODLevel } from '../../data/mock-config';
    23→
    24→// =============================================================================
    25→// TYPES
    26→// =============================================================================
    27→
    28→interface ViewportState {
    29→  zoom: number;
    30→  x: number;
    31→  y: number;
    32→}
    33→
    34→interface LayerOpacities {
    35→  strategic: number;
    36→  tactical: number;
    37→  operational: number;
    38→  execution: number;
    39→}
    40→
    41→// =============================================================================
    42→// CONSTANTS
    43→// =============================================================================
    44→
    45→const CROSSFADE_RANGE = 0.15; // Opacity transition range around threshold
    46→
    47→const LOD_COLORS: Record<LODLevel, string> = {
    48→  strategic: '#3b82f6',    // blue-500
    49→  tactical: '#8b5cf6',     // violet-500
    50→  operational: '#f59e0b',  // amber-500
    51→  execution: '#10b981',    // emerald-500
    52→};
    53→
    54→const LOD_DESCRIPTIONS: Record<LODLevel, string> = {
    55→  strategic: '12-Year Heatmap Overview',
    56→  tactical: 'Quarterly Stacked Bars',
    57→  operational: 'Monthly DNA Gantt',
    58→  execution: 'Weekly Task Details',
    59→};
    60→
    61→// =============================================================================
    62→// OPACITY CALCULATION
    63→// =============================================================================
    64→
    65→/**
    66→ * Calculate layer opacities based on current zoom level.
    67→ * Uses smooth crossfade transitions near thresholds.
    68→ */
    69→function calculateLayerOpacities(zoom: number): LayerOpacities {
    70→  const { strategic, tactical, operational } = LOD_THRESHOLDS;
    71→
    72→  // Helper: smooth step function for crossfade
    73→  const smoothStep = (value: number, edge0: number, edge1: number): number => {
    74→    const t = Math.max(0, Math.min(1, (value - edge0) / (edge1 - edge0)));
    75→    return t * t * (3 - 2 * t); // Smooth Hermite interpolation
    76→  };
    77→
    78→  // Calculate fade factors for each threshold
    79→  const fadeStrategicToTactical = smoothStep(
    80→    zoom,
    81→    strategic - CROSSFADE_RANGE,
    82→    strategic + CROSSFADE_RANGE
    83→  );
    84→
    85→  const fadeTacticalToOperational = smoothStep(
    86→    zoom,
    87→    tactical - CROSSFADE_RANGE,
    88→    tactical + CROSSFADE_RANGE
    89→  );
    90→
    91→  const fadeOperationalToExecution = smoothStep(
    92→    zoom,
    93→    operational - CROSSFADE_RANGE,
    94→    operational + CROSSFADE_RANGE
    95→  );
    96→
    97→  // Calculate final opacities
    98→  return {
    99→    strategic: 1 - fadeStrategicToTactical,
   100→    tactical: fadeStrategicToTactical * (1 - fadeTacticalToOperational),
   101→    operational: fadeTacticalToOperational * (1 - fadeOperationalToExecution),
   102→    execution: fadeOperationalToExecution,
   103→  };
   104→}
   105→
   106→// =============================================================================
   107→// MOCK LOD LAYER COMPONENTS
   108→// =============================================================================
   109→
   110→interface LayerProps {
   111→  opacity: number;
   112→  zoom: number;
   113→}
   114→
   115→function StrategicLayer({ opacity, zoom }: LayerProps) {
   116→  if (opacity < 0.01) return null;
   117→
   118→  // Generate heatmap cells
   119→  const cells = useMemo(() => {
   120→    const items = [];
   121→    for (let row = 0; row < 8; row++) {
   122→      for (let col = 0; col < 12; col++) {
   123→        const intensity = Math.sin(row * 0.5 + col * 0.3) * 0.5 + 0.5;
   124→        items.push({ row, col, intensity });
   125→      }
   126→    }
   127→    return items;
   128→  }, []);
   129→
   130→  return (
   131→    <div
   132→      style={{
   133→        position: 'absolute',
   134→        inset: 0,
   135→        opacity,
   136→        transition: 'opacity 50ms ease-out',
   137→        display: 'grid',
   138→        gridTemplateColumns: 'repeat(12, 1fr)',
   139→        gridTemplateRows: 'repeat(8, 1fr)',
   140→        gap: 2,
   141→        padding: 40,
   142→      }}
   143→    >
   144→      {cells.map(({ row, col, intensity }) => (
   145→        <div
   146→          key={`${row}-${col}`}
   147→          style={{
   148→            background: `rgba(59, 130, 246, ${0.2 + intensity * 0.6})`,
   149→            borderRadius: 4,
   150→            display: 'flex',
   151→            alignItems: 'center',
   152→            justifyContent: 'center',
   153→            fontSize: 10,
   154→            color: intensity > 0.5 ? 'white' : COLORS.text.secondary,
   155→            fontWeight: 500,
   156→          }}
   157→        >
   158→          {Math.round(intensity * 100)}%
   159→        </div>
   160→      ))}
   161→    </div>
   162→  );
   163→}
   164→
   165→function TacticalLayer({ opacity, zoom }: LayerProps) {
   166→  if (opacity < 0.01) return null;
   167→
   168→  const bars = useMemo(() => {
   169→    const items = [];
   170→    for (let row = 0; row < 16; row++) {
   171→      const widths = [
   172→        20 + Math.random() * 30,
   173→        20 + Math.random() * 30,
   174→        20 + Math.random() * 30,
   175→      ];
   176→      items.push({ row, widths });
   177→    }
   178→    return items;
   179→  }, []);
   180→
   181→  return (
   182→    <div
   183→      style={{
   184→        position: 'absolute',
   185→        inset: 0,
   186→        opacity,
   187→        transition: 'opacity 50ms ease-out',
   188→        display: 'flex',
   189→        flexDirection: 'column',
   190→        gap: 4,
   191→        padding: 40,
   192→        overflow: 'hidden',
   193→      }}
   194→    >
   195→      {bars.map(({ row, widths }) => (
   196→        <div
   197→          key={row}
   198→          style={{
   199→            flex: 1,
   200→            display: 'flex',
   201→            gap: 2,
   202→            alignItems: 'center',
   203→          }}
   204→        >
   205→          <div style={{ width: 40, fontSize: 10, color: COLORS.text.secondary }}>
   206→            T-{String(row + 1).padStart(3, '0')}
   207→          </div>
   208→          <div style={{ flex: 1, display: 'flex', gap: 2 }}>
   209→            <div
   210→              style={{
   211→                width: `${widths[0]}%`,
   212→                height: '100%',
   213→                background: '#8b5cf6',
   214→                borderRadius: 2,
   215→              }}
   216→            />
   217→            <div
   218→              style={{
   219→                width: `${widths[1]}%`,
   220→                height: '100%',
   221→                background: '#a78bfa',
   222→                borderRadius: 2,
   223→              }}
   224→            />
   225→            <div
   226→              style={{
   227→                width: `${widths[2]}%`,
   228→                height: '100%',
   229→                background: '#c4b5fd',
   230→                borderRadius: 2,
   231→              }}
   232→            />
   233→          </div>
   234→        </div>
   235→      ))}
   236→    </div>
   237→  );
   238→}
   239→
   240→function OperationalLayer({ opacity, zoom }: LayerProps) {
   241→  if (opacity < 0.01) return null;
   242→
   243→  const tasks = useMemo(() => {
   244→    const items = [];
   245→    for (let row = 0; row < 20; row++) {
   246→      const taskCount = 3 + Math.floor(Math.random() * 5);
   247→      const rowTasks = [];
   248→      let x = 40;
   249→      for (let t = 0; t < taskCount; t++) {
   250→        const width = 30 + Math.random() * 80;
   251→        const gap = 5 + Math.random() * 20;
   252→        rowTasks.push({ x, width, type: t % 3 });
   253→        x += width + gap;
   254→      }
   255→      items.push({ row, tasks: rowTasks });
   256→    }
   257→    return items;
   258→  }, []);
   259→
   260→  const typeColors = ['#f59e0b', '#fb923c', '#fbbf24'];
   261→
   262→  return (
   263→    <div
   264→      style={{
   265→        position: 'absolute',
   266→        inset: 0,
   267→        opacity,
   268→        transition: 'opacity 50ms ease-out',
   269→        display: 'flex',
   270→        flexDirection: 'column',
   271→        gap: 2,
   272→        padding: '40px 10px',
   273→        overflow: 'hidden',
   274→      }}
   275→    >
   276→      {tasks.map(({ row, tasks: rowTasks }) => (
   277→        <div
   278→          key={row}
   279→          style={{
   280→            flex: 1,
   281→            position: 'relative',
   282→            background: COLORS.bg.tertiary,
   283→            borderRadius: 2,
   284→          }}
   285→        >
   286→          {rowTasks.map((task, i) => (
   287→            <div
   288→              key={i}
   289→              style={{
   290→                position: 'absolute',
   291→                left: task.x,
   292→                top: 2,
   293→                bottom: 2,
   294→                width: task.width,
   295→                background: typeColors[task.type],
   296→                borderRadius: 3,
   297→              }}
   298→            />
   299→          ))}
   300→        </div>
   301→      ))}
   302→    </div>
   303→  );
   304→}
   305→
   306→function ExecutionLayer({ opacity, zoom }: LayerProps) {
   307→  if (opacity < 0.01) return null;
   308→
   309→  const cards = useMemo(() => {
   310→    const items = [];
   311→    for (let row = 0; row < 6; row++) {
   312→      for (let col = 0; col < 3; col++) {
   313→        items.push({
   314→          row,
   315→          col,
   316→          train: `K-${String(row * 3 + col + 1).padStart(3, '0')}`,
   317→          task: ['PM1', 'PM2', 'PM3', 'Overhaul'][Math.floor(Math.random() * 4)],
   318→          status: ['scheduled', 'in-progress', 'completed'][Math.floor(Math.random() * 3)],
   319→        });
   320→      }
   321→    }
   322→    return items;
   323→  }, []);
   324→
   325→  const statusColors = {
