   339→        gridTemplateColumns: 'repeat(3, 1fr)',
   340→        gridTemplateRows: 'repeat(6, 1fr)',
   341→        gap: 8,
   342→        padding: 40,
   343→      }}
   344→    >
   345→      {cards.map(({ row, col, train, task, status }) => (
