   358→          <Tag
   359→            minimal
   360→            style={{
   361→              background: statusColors[status as keyof typeof statusColors],
   362→              color: 'white',
   363→              fontSize: 9,
   364→            }}
   365→          >
   366→            {status}
   367→          </Tag>
   368→        </Card>
   369→      ))}
   370→    </div>
   371→  );
   372→}
