    10→ * 3. Color interpolation for utilization visualization
    11→ * 4. Hover interaction for cell tooltips
    12→ */
    13→
    14→import React, { useState, useMemo, useCallback } from 'react';
    15→import type { Meta, StoryObj } from '@storybook/react';
    16→import DeckGL from '@deck.gl/react';
    17→import { OrthographicView } from '@deck.gl/core';
