    19→import { Card, Tag, Intent, Divider, Button, ButtonGroup, Slider } from '@blueprintjs/core';
    20→
    21→import { generateMockData, type AggregatedCell } from '../../data/mock-generator';
    22→import { COLORS, TOTAL_TRAINS, TIME_RANGE } from '../../data/mock-config';
    23→
    24→// =============================================================================
    25→// TYPES
    26→// =============================================================================
    27→
    28→interface TooltipInfo {
    29→  x: number;
    30→  y: number;
    31→  cell: AggregatedCell | null;
    32→}
    33→
    34→interface ViewState {
    35→  target: [number, number];
    36→  zoom: number;
    37→}
    38→
    39→// =============================================================================
    40→// CONSTANTS
    41→// =============================================================================
    42→
    43→const CELL_WIDTH = 30; // pixels per quarter
    44→const CELL_HEIGHT = 8; // pixels per train
    45→const GRID_WIDTH = TIME_RANGE.quarters * CELL_WIDTH; // 48 * 30 = 1440
    46→const GRID_HEIGHT = TOTAL_TRAINS * CELL_HEIGHT; // 128 * 8 = 1024
    47→
    48→// Color interpolation thresholds
    49→const UTILIZATION_THRESHOLDS = {
    50→  low: 20,
    51→  medium: 50,
    52→  high: 80,
    53→};
    54→
    55→// =============================================================================
    56→// COLOR UTILITIES
    57→// =============================================================================
    58→
    59→function hexToRgb(hex: string): [number, number, number] {
    60→  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    61→  return result
    62→    ? [
    63→        parseInt(result[1], 16),
    64→        parseInt(result[2], 16),
    65→        parseInt(result[3], 16),
    66→      ]
    67→    : [128, 128, 128];
    68→}
    69→
    70→function interpolateColor(
    71→  color1: [number, number, number],
    72→  color2: [number, number, number],
    73→  t: number
    74→): [number, number, number, number] {
    75→  return [
    76→    Math.round(color1[0] + (color2[0] - color1[0]) * t),
    77→    Math.round(color1[1] + (color2[1] - color1[1]) * t),
    78→    Math.round(color1[2] + (color2[2] - color1[2]) * t),
    79→    255,
    80→  ];
    81→}
    82→
    83→function getUtilizationColor(utilization: number, hasOverhaul: boolean): [number, number, number, number] {
    84→  // Overhaul cells get special color
    85→  if (hasOverhaul) {
    86→    return [251, 146, 60, 255]; // orange-400
    87→  }
    88→
    89→  const low = hexToRgb(COLORS.heatmap.low);
    90→  const medium = hexToRgb(COLORS.heatmap.medium);
    91→  const high = hexToRgb(COLORS.heatmap.high);
    92→  const critical = hexToRgb(COLORS.heatmap.critical);
    93→
    94→  if (utilization < UTILIZATION_THRESHOLDS.low) {
    95→    const t = utilization / UTILIZATION_THRESHOLDS.low;
    96→    return interpolateColor(low, medium, t);
    97→  } else if (utilization < UTILIZATION_THRESHOLDS.medium) {
    98→    const t = (utilization - UTILIZATION_THRESHOLDS.low) /
    99→      (UTILIZATION_THRESHOLDS.medium - UTILIZATION_THRESHOLDS.low);
   100→    return interpolateColor(medium, high, t);
   101→  } else if (utilization < UTILIZATION_THRESHOLDS.high) {
   102→    const t = (utilization - UTILIZATION_THRESHOLDS.medium) /
   103→      (UTILIZATION_THRESHOLDS.high - UTILIZATION_THRESHOLDS.medium);
   104→    return interpolateColor(high, critical, t);
   105→  } else {
   106→    return [...hexToRgb(COLORS.heatmap.critical), 255] as [number, number, number, number];
   107→  }
   108→}
   109→
   110→// =============================================================================
   111→// CELL POLYGON GENERATION
   112→// =============================================================================
   113→
   114→function createCellPolygon(cell: AggregatedCell): number[][] {
   115→  const x = cell.periodIndex * CELL_WIDTH;
   116→  const y = cell.trainIndex * CELL_HEIGHT;
   117→
   118→  // Create rectangle polygon with small gap for grid effect
   119→  const gap = 1;
   120→  return [
   121→    [x + gap, y + gap],
   122→    [x + CELL_WIDTH - gap, y + gap],
   123→    [x + CELL_WIDTH - gap, y + CELL_HEIGHT - gap],
   124→    [x + gap, y + CELL_HEIGHT - gap],
   125→  ];
   126→}
   127→
   128→// =============================================================================
   129→// TOOLTIP COMPONENT
   130→// =============================================================================
   131→
   132→function CellTooltip({ info }: { info: TooltipInfo }) {
   133→  if (!info.cell) return null;
   134→
   135→  const quarterYear = Math.floor(info.cell.periodIndex / 4) + 2024;
   136→  const quarter = (info.cell.periodIndex % 4) + 1;
   137→  const trainIndex = info.cell.trainIndex;
   138→
   139→  // Determine fleet
   140→  const isKinki = trainIndex < 49;
   141→  const fleetName = isKinki ? 'Kinki Sharyo' : 'Alstom';
   142→  const fleetIndex = isKinki ? trainIndex + 1 : trainIndex - 49 + 1;
   143→  const trainId = isKinki ? `K-${String(fleetIndex).padStart(3, '0')}` : `A-${String(fleetIndex).padStart(3, '0')}`;
   144→
   145→  return (
   146→    <div
   147→      style={{
   148→        position: 'absolute',
   149→        left: info.x + 10,
   150→        top: info.y + 10,
   151→        pointerEvents: 'none',
   152→        zIndex: 1000,
