function DeckGLHeatmapDemo() {
  // Generate data once
  const mockData = useMemo(() => generateMockData(), []);

  // View state for pan/zoom
  const [viewState, setViewState] = useState<ViewState>({
    target: [GRID_WIDTH / 2, GRID_HEIGHT / 2],
    zoom: 0,
  });

  // Tooltip state
  const [tooltip, setTooltip] = useState<TooltipInfo>({ x: 0, y: 0, cell: null });

  // Create cell data with polygons
  const cellData = useMemo(() => {
    return mockData.aggregatedByQuarter.map((cell) => ({
      ...cell,
      polygon: createCellPolygon(cell),
      color: getUtilizationColor(cell.utilizationPercent, cell.hasOverhaul),
    }));
  }, [mockData]);

  // deck.gl layers
  const layers = useMemo(() => {
    return [
      new SolidPolygonLayer({
        id: 'heatmap-cells',
        data: cellData,
        getPolygon: (d) => d.polygon,
        getFillColor: (d) => d.color,
        pickable: true,
        extruded: false,
        // Performance optimizations
        updateTriggers: {
          getFillColor: [cellData],
        },
      }),
    ];
  }, [cellData]);

  // Handle hover
  const handleHover = useCallback((info: any) => {
    if (info.object) {
      setTooltip({
        x: info.x,
        y: info.y,
        cell: info.object as AggregatedCell,
      });
    } else {
      setTooltip({ x: 0, y: 0, cell: null });
    }
  }, []);

  // View controls
  const handleZoomIn = useCallback(() => {
    setViewState((prev) => ({ ...prev, zoom: Math.min(prev.zoom + 0.5, 4) }));
  }, []);

  const handleZoomOut = useCallback(() => {
    setViewState((prev) => ({ ...prev, zoom: Math.max(prev.zoom - 0.5, -2) }));
  }, []);

  const handleReset = useCallback(() => {
    setViewState({ target: [GRID_WIDTH / 2, GRID_HEIGHT / 2], zoom: 0 });
  }, []);

  return (
    <div style={{ width: '100%', height: '100vh', position: 'relative', background: COLORS.bg.tertiary }}>
      {/* deck.gl Canvas */}
      <div style={{ position: 'absolute', top: 24, left: 60, right: 0, bottom: 0 }}>
        <DeckGL
          views={new OrthographicView({ id: 'main' })}
          initialViewState={viewState}
          onViewStateChange={({ viewState: vs }) => setViewState(vs as ViewState)}
          controller={true}
          layers={layers}
          onHover={handleHover}
          getCursor={({ isHovering }) => (isHovering ? 'pointer' : 'grab')}
        />
      </div>

      {/* Axis labels */}
      <YearAxis viewState={viewState} />
      <TrainAxis viewState={viewState} />

      {/* Corner spacer */}
      <div
        style={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: 60,
          height: 24,
          background: COLORS.bg.secondary,
          borderRight: `1px solid ${COLORS.border.default}`,
          borderBottom: `1px solid ${COLORS.border.default}`,
          zIndex: 60,
        }}
      />

      {/* UI Overlays */}
      <HeatmapLegend />
      <StatsPanel data={mockData} />

      {/* Zoom Controls */}
      <Card style={{ position: 'absolute', bottom: 10, right: 10, padding: 8, zIndex: 100 }}>
        <ButtonGroup vertical>
          <Button icon="zoom-in" onClick={handleZoomIn} title="Zoom In" />
          <Button icon="zoom-out" onClick={handleZoomOut} title="Zoom Out" />
          <Button icon="home" onClick={handleReset} title="Reset View" />
        </ButtonGroup>
        <div style={{ textAlign: 'center', marginTop: 8, fontSize: 10, color: COLORS.text.secondary }}>
          Zoom: {Math.pow(2, viewState.zoom).toFixed(2)}x
        </div>
      </Card>

      {/* Tooltip */}
      <CellTooltip info={tooltip} />
    </div>
  );
}

