content.content:
     1→/**
     2→ * FractalCanvas Component
     3→ *
     4→ * The complete semantic zoom visualization integrating all 4 LOD layers:
     5→ * - Strategic (< 0.3x): 12-year heatmap overview
     6→ * - Tactical (0.3-1.0x): Monthly stacked bars
     7→ * - Operational (1.0-3.0x): DNA-style task blocks
     8→ * - Execution (> 3.0x): Detailed task cards
     9→ *
    10→ * Features smooth crossfade transitions between LOD levels.
    11→ */
    12→
    13→import React, { useMemo, useState, useCallback, useRef, useEffect } from 'react';
    14→import { Card, Tag, Intent, Slider, Button, ButtonGroup, Navbar, NavbarGroup, NavbarHeading, NavbarDivider, Alignment } from '@blueprintjs/core';
    15→import DeckGL from '@deck.gl/react';
    16→import { OrthographicView } from '@deck.gl/core';
    17→import { SolidPolygonLayer } from '@deck.gl/layers';
    18→import type { PickingInfo } from '@deck.gl/core';
    19→import type { Task, Train, AggregatedCell } from '../data/mock-generator';
    20→import { generateMockData, getTasksInRange } from '../data/mock-generator';
    21→import { MAINTENANCE_TYPES, MAINTENANCE_TYPE_MAP, TIME_RANGE, COLORS } from '../data/mock-config';
    22→
    23→// =============================================================================
    24→// TYPES
    25→// =============================================================================
    26→
    27→export interface FractalCanvasProps {
    28→  /** Width of the viewport */
    29→  width: number;
    30→  /** Height of the viewport */
    31→  height: number;
    32→  /** Initial zoom level */
    33→  initialZoom?: number;
    34→}
    35→
    36→type LODLevel = 'strategic' | 'tactical' | 'operational' | 'execution';
    37→
    38→interface ViewState {
    39→  target: [number, number, number];
    40→  zoom: number;
    41→}
    42→
    43→// =============================================================================
    44→// CONSTANTS
    45→// =============================================================================
    46→
    47→const LOD_THRESHOLDS = {
    48→  strategic: { max: 0.3 },
    49→  tactical: { min: 0.3, max: 1.0 },
    50→  operational: { min: 1.0, max: 3.0 },
    51→  execution: { min: 3.0 },
    52→};
    53→
    54→const TRANSITION_RANGE = 0.15; // 15% overlap for crossfade
    55→
    56→// Strategic layer constants
    57→const STRATEGIC_CELL_WIDTH = 30; // pixels per quarter
    58→const STRATEGIC_CELL_HEIGHT = 8; // pixels per train
    59→
    60→// Tactical layer constants
    61→const TACTICAL_CELL_WIDTH = 20; // pixels per month
    62→const TACTICAL_CELL_HEIGHT = 16; // pixels per train
    63→
    64→// Operational layer constants
    65→const OPERATIONAL_PX_PER_DAY = 8;
    66→const OPERATIONAL_PX_PER_TRAIN = 28;
    67→
    68→// =============================================================================
    69→// HELPERS
    70→// =============================================================================
    71→
    72→function getLODLevel(zoom: number): LODLevel {
    73→  if (zoom < LOD_THRESHOLDS.strategic.max) return 'strategic';
    74→  if (zoom < LOD_THRESHOLDS.tactical.max) return 'tactical';
    75→  if (zoom < LOD_THRESHOLDS.operational.max) return 'operational';
    76→  return 'execution';
    77→}
    78→
    79→function getLODOpacity(zoom: number, level: LODLevel): number {
    80→  const thresholds = LOD_THRESHOLDS[level];
    81→
    82→  if (level === 'strategic') {
    83→    if (zoom <= thresholds.max - TRANSITION_RANGE) return 1;
    84→    if (zoom >= thresholds.max) return 0;
    85→    return 1 - (zoom - (thresholds.max - TRANSITION_RANGE)) / TRANSITION_RANGE;
    86→  }
    87→
    88→  if (level === 'tactical') {
    89→    const fadeIn = zoom < thresholds.min! + TRANSITION_RANGE
    90→      ? (zoom - thresholds.min!) / TRANSITION_RANGE
    91→      : 1;
    92→    const fadeOut = zoom > thresholds.max - TRANSITION_RANGE
    93→      ? 1 - (zoom - (thresholds.max - TRANSITION_RANGE)) / TRANSITION_RANGE
    94→      : 1;
    95→    return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
    96→  }
    97→
    98→  if (level === 'operational') {
    99→    const fadeIn = zoom < thresholds.min! + TRANSITION_RANGE
   100→      ? (zoom - thresholds.min!) / TRANSITION_RANGE
   101→      : 1;
   102→    const fadeOut = zoom > thresholds.max - TRANSITION_RANGE
   103→      ? 1 - (zoom - (thresholds.max - TRANSITION_RANGE)) / TRANSITION_RANGE
   104→      : 1;
   105→    return Math.max(0, Math.min(1, Math.min(fadeIn, fadeOut)));
   106→  }
   107→
   108→  if (level === 'execution') {
   109→    if (zoom >= thresholds.min! + TRANSITION_RANGE) return 1;
   110→    if (zoom <= thresholds.min!) return 0;
   111→    return (zoom - thresholds.min!) / TRANSITION_RANGE;
   112→  }
   113→
   114→  return 0;
   115→}
   116→
   117→function daysBetween(start: Date, end: Date): number {
   118→  return Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
   119→}
   120→
   121→function hexToRgba(hex: string, alpha: number = 255): [number, number, number, number] {
   122→  const result = /^#?([a-f\\d]{2})([a-f\\d]{2})([a-f\\d]{2})$/i.exec(hex);
   123→  if (result) {
   124→    return [
   125→      parseInt(result[1], 16),
   126→      parseInt(result[2], 16),
   127→      parseInt(result[3], 16),
   128→      alpha,
   129→    ];
   130→  }
   131→  return [128, 128, 128, alpha];
   132→}
   133→
   134→// =============================================================================
   135→// COMPONENT
   136→// =============================================================================
   137→
   138→export const FractalCanvas: React.FC<FractalCanvasProps> = ({
   139→  width,
   140→  height,
   141→  initialZoom = 0.5,
   142→}) => {
   143→  // Generate mock data
   144→  const mockData = useMemo(() => generateMockData(), []);
   145→
   146→  // State
   147→  const [zoom, setZoom] = useState(initialZoom);
   148→  const [cameraX, setCameraX] = useState(0);
   149→  const [cameraY, setCameraY] = useState(0);
   150→  const [hoveredItem, setHoveredItem] = useState<Task | AggregatedCell | null>(null);
   151→
   152→  // Current LOD level
   153→  const currentLOD = getLODLevel(zoom);
   154→
   155→  // Calculate opacities for each layer
   156→  const opacities = useMemo(() => ({
   157→    strategic: getLODOpacity(zoom, 'strategic'),
   158→    tactical: getLODOpacity(zoom, 'tactical'),
   159→    operational: getLODOpacity(zoom, 'operational'),
   160→    execution: getLODOpacity(zoom, 'execution'),
   161→  }), [zoom]);
   162→
   163→  // Calculate world dimensions based on current LOD
   164→  const worldDimensions = useMemo(() => {
   165→    const totalDays = TIME_RANGE.years * 365;
   166→    const trainCount = mockData.trains.length;
   167→
   168→    return {
   169→      strategic: {
   170→        width: (TIME_RANGE.years * 4) * STRATEGIC_CELL_WIDTH,
   171→        height: trainCount * STRATEGIC_CELL_HEIGHT,
   172→      },
   173→      tactical: {
   174→        width: (TIME_RANGE.years * 12) * TACTICAL_CELL_WIDTH,
   175→        height: trainCount * TACTICAL_CELL_HEIGHT,
   176→      },
   177→      operational: {
   178→        width: totalDays * OPERATIONAL_PX_PER_DAY,
   179→        height: trainCount * OPERATIONAL_PX_PER_TRAIN,
   180→      },
   181→    };
   182→  }, [mockData.trains.length]);
   183→
   184→  // Create strategic layer (heatmap)
   185→  const strategicLayers = useMemo(() => {
   186→    if (opacities.strategic <= 0) return [];
   187→
   188→    return [
   189→      new SolidPolygonLayer<AggregatedCell>({
   190→        id: 'strategic-heatmap',
   191→        data: mockData.aggregatedByQuarter,
   192→        getPolygon: (d) => {
   193→          const x = d.periodIndex * STRATEGIC_CELL_WIDTH;
   194→          const y = d.trainIndex * STRATEGIC_CELL_HEIGHT;
   195→          return [
   196→            [x, y],
   197→            [x + STRATEGIC_CELL_WIDTH - 1, y],
   198→            [x + STRATEGIC_CELL_WIDTH - 1, y + STRATEGIC_CELL_HEIGHT - 1],
   199→            [x, y + STRATEGIC_CELL_HEIGHT - 1],
   200→          ];
   201→        },
   202→        getFillColor: (d) => {
   203→          const intensity = Math.min(1, d.utilizationPercent / 100);
   204→          // Yellow → Orange → Red gradient
   205→          if (intensity < 0.5) {
   206→            const t = intensity * 2;
   207→            return [255, Math.round(243 - t * 50), Math.round(196 - t * 100), 255 * opacities.strategic];
   208→          } else {
   209→            const t = (intensity - 0.5) * 2;
   210→            return [255, Math.round(193 - t * 100), Math.round(96 - t * 96), 255 * opacities.strategic];
   211→          }
   212→        },
   213→        pickable: true,
   214→        opacity: opacities.strategic,
   215→        updateTriggers: {
   216→          getFillColor: [opacities.strategic],
   217→        },
   218→      }),
   219→    ];
   220→  }, [mockData.aggregatedByQuarter, opacities.strategic]);
   221→
   222→  // Create tactical layer (monthly bars)
   223→  const tacticalLayers = useMemo(() => {
   224→    if (opacities.tactical <= 0) return [];
   225→
   226→    return [
   227→      new SolidPolygonLayer<AggregatedCell>({
   228→        id: 'tactical-bars',
   229→        data: mockData.aggregatedByMonth,
   230→        getPolygon: (d) => {
   231→          const x = d.periodIndex * TACTICAL_CELL_WIDTH;
   232→          const y = d.trainIndex * TACTICAL_CELL_HEIGHT;
   233→          const barHeight = (d.utilizationPercent / 100) * (TACTICAL_CELL_HEIGHT - 2);
   234→          return [
   235→            [x + 1, y + TACTICAL_CELL_HEIGHT - 1 - barHeight],
   236→            [x + TACTICAL_CELL_WIDTH - 2, y + TACTICAL_CELL_HEIGHT - 1 - barHeight],
   237→            [x + TACTICAL_CELL_WIDTH - 2, y + TACTICAL_CELL_HEIGHT - 1],
   238→            [x + 1, y + TACTICAL_CELL_HEIGHT - 1],
   239→          ];
   240→        },
   241→        getFillColor: (d) => {
   242→          if (d.hasConflict) return [239, 68, 68, 255 * opacities.tactical];
   243→          const intensity = Math.min(1, d.utilizationPercent / 100);
   244→          if (intensity > 0.8) return [239, 68, 68, 255 * opacities.tactical];
   245→          if (intensity > 0.6) return [251, 191, 36, 255 * opacities.tactical];
   246→          return [34, 197, 94, 255 * opacities.tactical];
   247→        },
   248→        pickable: true,
   249→        opacity: opacities.tactical,
   250→        updateTriggers: {
   251→          getFillColor: [opacities.tactical],
   252→        },
   253→      }),
   254→    ];
   255→  }, [mockData.aggregatedByMonth, opacities.tactical]);
   256→
   257→  // Create operational layer (task blocks)
   258→  const operationalLayers = useMemo(() => {
   259→    if (opacities.operational <= 0) return [];
   260→
   261→    interface TaskPolygon {
   262→      polygon: [number, number][];
   263→      task: Task;
   264→      color: [number, number, number, number];
   265→    }
   266→
   267→    const taskPolygons: TaskPolygon[] = mockData.tasks.map((task) => {
   268→      const startDay = daysBetween(TIME_RANGE.start, task.startDate);
   269→      const duration = Math.max(1, daysBetween(task.startDate, task.endDate));
   270→
   271→      const x = startDay * OPERATIONAL_PX_PER_DAY;
   272→      const y = task.trainIndex * OPERATIONAL_PX_PER_TRAIN + 4;
   273→      const w = duration * OPERATIONAL_PX_PER_DAY - 1;
   274→      const h = 20;
   275→
   276→      const mt = MAINTENANCE_TYPE_MAP.get(task.type);
   277→      const baseColor = mt?.color ?? COLORS.task.default;
   278→
   279→      return {
   280→        polygon: [
   281→          [x, y],
   282→          [x + w, y],
   283→          [x + w, y + h],
   284→          [x, y + h],
   285→        ],
   286→        task,
   287→        color: hexToRgba(baseColor, 255 * opacities.operational),
   288→      };
   289→    });
   290→
   291→    return [
   292→      // Background rows
   293→      new SolidPolygonLayer<{ polygon: [number, number][]; index: number }>({
   294→        id: 'operational-grid',
   295→        data: mockData.trains.map((_, i) => ({
   296→          polygon: [
   297→            [0, i * OPERATIONAL_PX_PER_TRAIN],
   298→            [worldDimensions.operational.width, i * OPERATIONAL_PX_PER_TRAIN],
   299→            [worldDimensions.operational.width, (i + 1) * OPERATIONAL_PX_PER_TRAIN - 1],
   300→            [0, (i + 1) * OPERATIONAL_PX_PER_TRAIN - 1],
   301→          ],
   302→          index: i,
   303→        })),
   304→        getPolygon: (d) => d.polygon,
   305→        getFillColor: (d) => d.index % 2 === 0
   306→          ? [250, 250, 250, 255 * opacities.operational]
   307→          : [245, 245, 245, 255 * opacities.operational],
   308→        pickable: false,
   309→        opacity: opacities.operational * 0.8,
   310→      }),
   311→      // Task bars
   312→      new SolidPolygonLayer<TaskPolygon>({
   313→        id: 'operational-tasks',
   314→        data: taskPolygons,
   315→        getPolygon: (d) => d.polygon,
   316→        getFillColor: (d) => {
   317→          if (d.task.hasConflict) return [239, 68, 68, 255 * opacities.operational];
   318→          return d.color;
   319→        },
   320→        pickable: true,
   321→        opacity: opacities.operational,
   322→        updateTriggers: {
   323→          getFillColor: [opacities.operational],
   324→        },
   325→      }),
   326→    ];
   327→  }, [mockData.tasks, mockData.trains.length, worldDimensions.operational.width, opacities.operational]);
   328→
   329→  // All deck.gl layers
   330→  const layers = useMemo(() => [
   331→    ...strategicLayers,
   332→    ...tacticalLayers,
   333→    ...operationalLayers,
   334→  ], [strategicLayers, tacticalLayers, operationalLayers]);
   335→
   336→  // View state - calculate target based on current LOD's world dimensions
   337→  const viewState: ViewState = useMemo(() => {
   338→    // Calculate world dimensions for current LOD
   339→    let worldWidth: number;
   340→    let worldHeight: number;
   341→
   342→    if (currentLOD === 'strategic') {
   343→      worldWidth = worldDimensions.strategic.width;
   344→      worldHeight = worldDimensions.strategic.height;
   345→    } else if (currentLOD === 'tactical') {
   346→      worldWidth = worldDimensions.tactical.width;
   347→      worldHeight = worldDimensions.tactical.height;
   348→    } else {
   349→      worldWidth = worldDimensions.operational.width;
   350→      worldHeight = worldDimensions.operational.height;
   351→    }
   352→
   353→    // Calculate scale factor from zoom
   354→    const scale = Math.pow(2, Math.log2(zoom));
   355→
   356→    // Calculate viewport size in world coordinates
   357→    const viewportWidth = (width - 100) / scale;
   358→    const viewportHeight = (height - 40) / scale;
   359→
   360→    // Center target - start at center of visible data, offset by camera position
   361→    const targetX = viewportWidth / 2 + cameraX * (worldWidth / mockData.trains.length);
   362→    const targetY = viewportHeight / 2 + cameraY * (worldHeight / mockData.trains.length);
   363→
   364→    return {
   365→      target: [targetX, targetY, 0],
   366→      zoom: Math.log2(zoom),
   367→    };
   368→  }, [cameraX, cameraY, zoom, width, height, currentLOD, worldDimensions, mockData.trains.length]);
   369→
   370→  // Handle zoom change
   371→  const handleZoomChange = useCallback((delta: number) => {
   372→    setZoom((z) => Math.max(0.1, Math.min(5, z + delta)));
   373→  }, []);
   374→
   375→  // Handle pan
   376→  const handlePan = useCallback((dx: number, dy: number) => {
   377→    setCameraX((x) => x + dx);
   378→    setCameraY((y) => Math.max(0, Math.min(mockData.trains.length - 1, y + dy)));
   379→  }, [mockData.trains.length]);
   380→
   381→  // View - memoize to prevent recreation on every render
   382→  const views = useMemo(() => new OrthographicView({
   383→    id: 'fractal-view',
   384→    flipY: false,
   385→    controller: true,
   386→  }), []);
   387→
   388→  // Get visible trains based on cameraY
   389→  const visibleTrains = useMemo(() => {
   390→    const startIndex = Math.max(0, Math.floor(cameraY));
   391→    const visibleCount = Math.ceil(height / 30) + 2;
   392→    return mockData.trains.slice(startIndex, startIndex + visibleCount);
   393→  }, [cameraY, height, mockData.trains]);
   394→
   395→  return (
   396→    <div style={{ width, height, position: 'relative', background: '#f4f4f5' }}>
   397→      {/* Navbar */}
   398→      <Navbar style={{ height: 40 }}>
   399→        <NavbarGroup align={Alignment.LEFT}>
   400→          <NavbarHeading style={{ fontSize: 14 }}>MMS Fractal Canvas</NavbarHeading>
   401→          <NavbarDivider />
   402→          <Tag
   403→            intent={
   404→              currentLOD === 'strategic' ? Intent.PRIMARY :
   405→              currentLOD === 'tactical' ? Intent.WARNING :
   406→              currentLOD === 'operational' ? Intent.SUCCESS :
   407→              Intent.DANGER
   408→            }
   409→            large
   410→          >
   411→            {currentLOD.toUpperCase()}
   412→          </Tag>
   413→        </NavbarGroup>
   414→        <NavbarGroup align={Alignment.RIGHT}>
   415→          <span style={{ fontSize: 12, marginRight: 8 }}>Zoom: {zoom.toFixed(2)}x</span>
   416→          <ButtonGroup>
   417→            <Button icon="minus" onClick={() => handleZoomChange(-0.1)} />
   418→            <Button icon="plus" onClick={() => handleZoomChange(0.1)} />
   419→            <Button icon="home" onClick={() => setZoom(initialZoom)} />
   420→          </ButtonGroup>
   421→        </NavbarGroup>
   422→      </Navbar>
   423→
   424→      {/* Main content area */}
   425→      <div style={{ display: 'flex', height: height - 40 }}>
   426→        {/* Sidebar - Train IDs */}
   427→        <Card
   428→          style={{
   429→            width: 100,
   430→            height: '100%',
   431→            borderRadius: 0,
   432→            padding: 0,
   433→            overflow: 'hidden',
   434→          }}
   435→        >
   436→          <div style={{ padding: 8, borderBottom: '1px solid #e2e8f0', fontWeight: 600, fontSize: 11 }}>
   437→            Trains
   438→          </div>
   439→          <div style={{ overflowY: 'auto', height: 'calc(100% - 32px)' }}>
   440→            {visibleTrains.map((train) => (
   441→              <div
   442→                key={train.id}
   443→                style={{
   444→                  padding: '6px 8px',
   445→                  borderBottom: '1px solid #f1f5f9',
   446→                  fontSize: 10,
   447→                }}
   448→              >
   449→                <div style={{ fontWeight: 500 }}>{train.name}</div>
   450→                <Tag
   451→                  minimal
   452→                  intent={train.fleetId === 'kinki' ? Intent.SUCCESS : Intent.PRIMARY}
   453→                  style={{ fontSize: 9 }}
   454→                >
   455→                  {train.fleetId === 'kinki' ? 'KNK' : 'ALT'}
   456→                </Tag>
   457→              </div>
   458→            ))}
   459→          </div>
   460→        </Card>
   461→
   462→        {/* Canvas area */}
   463→        <div style={{ flex: 1, position: 'relative' }}>
   464→          {/* Execution layer (HTML overlay) - only show at execution zoom */}
   465→          {opacities.execution > 0 && (
   466→            <ExecutionOverlay
   467→              tasks={mockData.tasks}
   468→              trains={mockData.trains}
   469→              cameraX={cameraX}
   470→              cameraY={cameraY}
   471→              zoom={zoom}
   472→              width={width - 100}
   473→              height={height - 40}
   474→              opacity={opacities.execution}
   475→            />
   476→          )}
   477→
   478→          {/* deck.gl layers for Strategic, Tactical, Operational */}
   479→          {(opacities.strategic > 0 || opacities.tactical > 0 || opacities.operational > 0) && (
   480→            <DeckGL
   481→              width={width - 100}
   482→              height={height - 40}
   483→              views={views}
   484→              viewState={viewState}
   485→              layers={layers}
   486→              getCursor={() => 'grab'}
   487→              style={{ opacity: Math.max(opacities.strategic, opacities.tactical, opacities.operational) }}
   488→            />
   489→          )}
   490→
   491→          {/* LOD opacity indicators */}
   492→          <div
   493→            style={{
   494→              position: 'absolute',
   495→              bottom: 16,
   496→              right: 16,
   497→              background: 'white',
   498→              padding: 12,
   499→              borderRadius: 8,
   500→              boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
   501→              fontSize: 11,
   502→            }}
   503→          >
   504→            <div style={{ fontWeight: 600, marginBottom: 8 }}>Layer Visibility</div>
   505→            <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
   506→              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   507→                <div
   508→                  style={{
   509→                    width: 40,
   510→                    height: 6,
   511→                    background: `linear-gradient(to right, #3b82f6 ${opacities.strategic * 100}%, #e5e7eb ${opacities.strategic * 100}%)`,
   512→                    borderRadius: 3,
   513→                  }}
   514→                />
   515→                <span>Strategic ({Math.round(opacities.strategic * 100)}%)</span>
   516→              </div>
   517→              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   518→                <div
   519→                  style={{
   520→                    width: 40,
   521→                    height: 6,
   522→                    background: `linear-gradient(to right, #f59e0b ${opacities.tactical * 100}%, #e5e7eb ${opacities.tactical * 100}%)`,
   523→                    borderRadius: 3,
   524→                  }}
   525→                />
   526→                <span>Tactical ({Math.round(opacities.tactical * 100)}%)</span>
   527→              </div>
   528→              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   529→                <div
   530→                  style={{
   531→                    width: 40,
   532→                    height: 6,
   533→                    background: `linear-gradient(to right, #22c55e ${opacities.operational * 100}%, #e5e7eb ${opacities.operational * 100}%)`,
   534→                    borderRadius: 3,
   535→                  }}
   536→                />
   537→                <span>Operational ({Math.round(opacities.operational * 100)}%)</span>
   538→              </div>
   539→              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   540→                <div
   541→                  style={{
   542→                    width: 40,
   543→                    height: 6,
   544→                    background: `linear-gradient(to right, #ef4444 ${opacities.execution * 100}%, #e5e7eb ${opacities.execution * 100}%)`,
   545→                    borderRadius: 3,
   546→                  }}
   547→                />
   548→                <span>Execution ({Math.round(opacities.execution * 100)}%)</span>
   549→              </div>
   550→            </div>
   551→          </div>
   552→
   553→          {/* Zoom slider */}
   554→          <Card
   555→            style={{
   556→              position: 'absolute',
   557→              bottom: 16,
   558→              left: 16,
   559→              padding: 12,
   560→              width: 200,
   561→            }}
   562→          >
   563→            <div style={{ fontSize: 11, fontWeight: 600, marginBottom: 8 }}>
   564→              Zoom Level
   565→            </div>
   566→            <Slider
   567→              min={0.1}
   568→              max={5}
   569→              stepSize={0.05}
   570→              value={zoom}
   571→              onChange={setZoom}
   572→              labelRenderer={(val) => `${val.toFixed(1)}x`}
   573→              labelStepSize={1}
   574→            />
   575→            <div style={{ fontSize: 10, color: '#666', marginTop: 8 }}>
   576→              <div>Strategic: &lt; 0.3x</div>
   577→              <div>Tactical: 0.3 - 1.0x</div>
   578→              <div>Operational: 1.0 - 3.0x</div>
   579→              <div>Execution: &gt; 3.0x</div>
   580→            </div>
   581→          </Card>
   582→        </div>
   583→      </div>
   584→    </div>
   585→  );
   586→};
   587→
   588→// =============================================================================
   589→// EXECUTION OVERLAY (HTML-based for detailed view)
   590→// =============================================================================
   591→
   592→interface ExecutionOverlayProps {
   593→  tasks: Task[];
   594→  trains: Train[];
   595→  cameraX: number;
   596→  cameraY: number;
   597→  zoom: number;
   598→  width: number;
   599→  height: number;
   600→  opacity: number;
   601→}
   602→
   603→const ExecutionOverlay: React.FC<ExecutionOverlayProps> = ({
   604→  tasks,
   605→  trains,
   606→  cameraX,
   607→  cameraY,
   608→  zoom,
   609→  width,
   610→  height,
   611→  opacity,
   612→}) => {
   613→  const ROW_HEIGHT = 80;
   614→  const EXEC_PX_PER_DAY = 80;
   615→  const HEADER_HEIGHT = 50;
   616→
   617→  // Filter tasks for visible range
   618→  const visibleTasks = useMemo(() => {
   619→    const startTrain = Math.max(0, Math.floor(cameraY));
   620→    const endTrain = Math.min(trains.length - 1, Math.ceil(cameraY + height / ROW_HEIGHT));
   621→
   622→    return tasks.filter((task) => {
   623→      return task.trainIndex >= startTrain && task.trainIndex <= endTrain;
   624→    }).slice(0, 50); // Limit for performance
   625→  }, [tasks, trains.length, cameraY, height]);
   626→
   627→  // Calculate earliest task day
   628→  const earliestTaskDay = useMemo(() => {
   629→    if (visibleTasks.length === 0) return 0;
   630→    const days = visibleTasks.map(t => daysBetween(TIME_RANGE.start, t.startDate));
   631→    return Math.min(...days);
   632→  }, [visibleTasks]);
   633→
   634→  return (
   635→    <div
   636→      style={{
   637→        position: 'absolute',
   638→        top: 0,
   639→        left: 0,
   640→        width,
   641→        height,
   642→        overflow: 'hidden',
   643→        background: '#f8fafc',
   644→        opacity,
   645→        pointerEvents: opacity > 0.5 ? 'auto' : 'none',
   646→      }}
   647→    >
   648→      {/* Header */}
   649→      <div
   650→        style={{
   651→          position: 'absolute',
   652→          top: 0,
   653→          left: 0,
   654→          right: 0,
   655→          height: HEADER_HEIGHT,
   656→          background: 'white',
   657→          borderBottom: '1px solid #e2e8f0',
   658→          display: 'flex',
   659→          alignItems: 'center',
   660→          paddingLeft: 16,
   661→          fontWeight: 600,
   662→          fontSize: 12,
   663→        }}
   664→      >
   665→        Execution View - {visibleTasks.length} tasks visible
   666→      </div>
   667→
   668→      {/* Task cards */}
   669→      <div
   670→        style={{
   671→          position: 'absolute',
   672→          top: HEADER_HEIGHT,
   673→          left: 0,
   674→          right: 0,
   675→          bottom: 0,
   676→          overflow: 'auto',
   677→        }}
   678→      >
   679→        {visibleTasks.map((task) => {
   680→          const startDay = daysBetween(TIME_RANGE.start, task.startDate);
   681→          const duration = Math.max(1, daysBetween(task.startDate, task.endDate));
   682→          const dayOffset = startDay - earliestTaskDay;
   683→
   684→          const x = 16 + dayOffset * EXEC_PX_PER_DAY;
   685→          const y = (task.trainIndex - Math.floor(cameraY)) * ROW_HEIGHT + 10;
   686→          const w = Math.max(duration * EXEC_PX_PER_DAY - 10, 150);
   687→
   688→          const mt = MAINTENANCE_TYPE_MAP.get(task.type);
   689→
   690→          return (
   691→            <Card
   692→              key={task.id}
   693→              interactive
   694→              elevation={1}
   695→              style={{
   696→                position: 'absolute',
   697→                left: x,
   698→                top: y,
   699→                width: w,
   700→                height: 60,
   701→                padding: 8,
   702→                borderLeft: `4px solid ${mt?.color ?? '#94a3b8'}`,
   703→                overflow: 'hidden',
   704→              }}
   705→            >
   706→              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 4 }}>
   707→                <div style={{ fontSize: 10, fontWeight: 600, color: '#1e293b' }}>
   708→                  {task.name}
   709→                </div>
   710→                <Tag
   711→                  minimal
   712→                  intent={
   713→                    task.status === 'completed' ? Intent.SUCCESS :
   714→                    task.status === 'in-progress' ? Intent.PRIMARY :
   715→                    task.status === 'overdue' ? Intent.DANGER :
   716→                    Intent.NONE
   717→                  }
   718→                  style={{ fontSize: 8 }}
   719→                >
   720→                  {task.status}
   721→                </Tag>
   722→              </div>
   723→              <div style={{ fontSize: 9, color: '#64748b' }}>
   724→                {task.durationHours}h • {task.manHours}mh
   725→              </div>
   726→              {task.hasConflict && (
   727→                <Tag intent={Intent.DANGER} style={{ position: 'absolute', top: 4, right: 4, fontSize: 8 }}>!</Tag>
   728→              )}
   729→            </Card>
   730→          );
   731→        })}
   732→      </div>
   733→    </div>
   734→  );
   735→};
   736→
   737→export default FractalCanvas;
   738→

