   100→   100→### 2.3 Drag Implementation Pattern
   101→   101→
   102→   102→```typescript
   103→   103→interface DragState {
   104→   104→  isDragging: boolean;
   105→   105→  startX: number;
   106→   106→  startY: number;
   107→   107→  lastX: number;
   108→   108→  lastY: number;
   109→   109→  velocityX: number;
   110→   110→  velocityY: number;
   111→   111→  lastTime: number;
   112→   112→}
   113→   113→
   114→   114→// Calculate velocity during drag for momentum
   115→   115→function onMouseMove(e: MouseEvent, state: DragState) {
   116→   116→  const now = performance.now();
   117→   117→  const dt = now - state.lastTime;
   118→   118→
   119→   119→  if (dt > 0) {
   120→   120→    state.velocityX = (e.clientX - state.lastX) / dt;
   121→   121→    state.velocityY = (e.clientY - state.lastY) / dt;
   122→   122→  }
   123→   123→
   124→   124→  state.lastX = e.clientX;
   125→   125→  state.lastY = e.clientY;
   126→   126→  state.lastTime = now;
   127→   127→}
   128→   128→```
   129→   129→
   130→   130→### 2.4 Double-Click Detection
   131→   131→
   132→   132→```typescript
   133→   133→const DOUBLE_CLICK_THRESHOLD = 300; // ms
   134→   134→let lastClickTime = 0;
   135→   135→
   136→   136→function onClick(e: MouseEvent) {
   137→   137→  const now = Date.now();
   138→   138→  if (now - lastClickTime < DOUBLE_CLICK_THRESHOLD) {
   139→   139→    handleDoubleClick(e);
   140→   140→  }
   141→   141→  lastClickTime = now;
   142→   142→}
   143→   143→```
