   147→   147→## 3. Touch Events Reference
   148→   148→
   149→   149→### 3.1 Touch Event Types
   150→   150→
   151→   151→| Event | Triggers | Notes |
   152→   152→|-------|----------|-------|
   153→   153→| `touchstart` | Finger touches screen | One or more touches |
   154→   154→| `touchmove` | Finger moves on screen | Fires frequently |
   155→   155→| `touchend` | Finger lifts from screen | |
   156→   156→| `touchcancel` | Touch interrupted | System event, incoming call |
   157→   157→
   158→   158→### 3.2 Pointer Events (Modern, Unified)
   159→   159→
   160→   160→Pointer Events unify mouse, touch, and pen input:
   161→   161→
   162→   162→| Event | Equivalent Touch/Mouse |
   163→   163→|-------|------------------------|
   164→   164→| `pointerdown` | `touchstart` / `mousedown` |
   165→   165→| `pointermove` | `touchmove` / `mousemove` |
   166→   166→| `pointerup` | `touchend` / `mouseup` |
   167→   167→| `pointercancel` | `touchcancel` |
   168→   168→| `pointerenter` | `mouseenter` |
   169→   169→| `pointerleave` | `mouseleave` |
   170→   170→
   171→   171→**Key Properties:**
   172→   172→- `pointerId`: Unique identifier for each contact
   173→   173→- `pointerType`: "mouse", "touch", "pen"
   174→   174→- `isPrimary`: True for first finger/primary button
   175→   175→- `pressure`: 0.0 to 1.0 (pen pressure)
   176→   176→- `width`, `height`: Contact area size
   177→   177→
   178→   178→### 3.3 Pinch-to-Zoom Algorithm
   179→   179→
   180→   180→```typescript
   181→   181→// Cache active pointers
   182→   182→const evCache: PointerEvent[] = [];
   183→   183→let prevDist = -1;
   184→   184→
   185→   185→function onPointerDown(ev: PointerEvent) {
   186→   186→  evCache.push(ev);
   187→   187→}
   188→   188→
   189→   189→function onPointerMove(ev: PointerEvent) {
   190→   190→  // Update cached pointer
   191→   191→  const idx = evCache.findIndex(e => e.pointerId === ev.pointerId);
   192→   192→  if (idx >= 0) evCache[idx] = ev;
   193→   193→
   194→   194→  // Pinch gesture requires exactly 2 pointers
   195→   195→  if (evCache.length === 2) {
   196→   196→    const dx = evCache[0].clientX - evCache[1].clientX;
   197→   197→    const dy = evCache[0].clientY - evCache[1].clientY;
   198→   198→    const curDist = Math.sqrt(dx * dx + dy * dy);
   199→   199→
   200→   200→    if (prevDist > 0) {
   201→   201→      const scale = curDist / prevDist;
   202→   202→      // scale > 1 = zoom in, scale < 1 = zoom out
   203→   203→      handlePinchZoom(scale, getMidpoint(evCache[0], evCache[1]));
   204→   204→    }
   205→   205→
   206→   206→    prevDist = curDist;
   207→   207→  }
   208→   208→}
   209→   209→
   210→   210→function onPointerUp(ev: PointerEvent) {
   211→   211→  const idx = evCache.findIndex(e => e.pointerId === ev.pointerId);
   212→   212→  if (idx >= 0) evCache.splice(idx, 1);
   213→   213→  if (evCache.length < 2) prevDist = -1;
   214→   214→}
   215→   215→
   216→   216→function getMidpoint(a: PointerEvent, b: PointerEvent) {
   217→   217→  return {
   218→   218→    x: (a.clientX + b.clientX) / 2,
   219→   219→    y: (a.clientY + b.clientY) / 2
   220→   220→  };
   221→   221→}
   222→   222→```
   223→   223→
