   236→   236→
   237→   237→## 4. Wheel Event Normalization
   238→   238→
   239→   239→### 4.1 The Problem
   240→   240→
   241→   241→Different browsers/platforms report wildly different `deltaY` values:
   242→   242→
   243→   243→| Environment | deltaY per "tick" |
   244→   244→|-------------|-------------------|
   245→   245→| Chrome (Windows) | 100-120 |
   246→   246→| Chrome (macOS trackpad) | 1-5 (many events) |
   247→   247→| Firefox (Windows) | 3 (lines mode) |
   248→   248→| Firefox (macOS) | 1-2 |
   249→   249→| Safari | 1-12 |
   250→   250→
   251→   251→### 4.2 deltaMode Values
   252→   252→
   253→   253→```typescript
   254→   254→enum WheelDeltaMode {
   255→   255→  DOM_DELTA_PIXEL = 0,  // deltaY is in pixels
   256→   256→  DOM_DELTA_LINE = 1,   // deltaY is in lines
   257→   257→  DOM_DELTA_PAGE = 2    // deltaY is in pages
   258→   258→}
   259→   259→```
   260→   260→
   261→   261→### 4.3 Facebook's Normalization Algorithm
   262→   262→
   263→   263→```typescript
   264→   264→// Constants for normalization
   265→   265→const PIXEL_STEP = 10;
   266→   266→const LINE_HEIGHT = 40;
   267→   267→const PAGE_HEIGHT = 800;
   268→   268→
   269→   269→interface NormalizedWheel {
   270→   270→  spinX: number;   // Normalized spin (-1 to 1)
   271→   271→  spinY: number;   // Normalized spin (-1 to 1)
   272→   272→  pixelX: number;  // Normalized pixels
   273→   273→  pixelY: number;  // Normalized pixels
   274→   274→}
   275→   275→
   276→   276→function normalizeWheel(event: WheelEvent): NormalizedWheel {
   277→   277→  let sX = 0, sY = 0;   // spin
   278→   278→  let pX = 0, pY = 0;   // pixel
   279→   279→
   280→   280→  // Modern wheel event
   281→   281→  if ('deltaY' in event) {
   282→   282→    pX = event.deltaX;
   283→   283→    pY = event.deltaY;
   284→   284→
   285→   285→    // Convert based on deltaMode
   286→   286→    if (event.deltaMode === 1) {        // LINE mode
   287→   287→      pX *= LINE_HEIGHT;
   288→   288→      pY *= LINE_HEIGHT;
   289→   289→    } else if (event.deltaMode === 2) { // PAGE mode
   290→   290→      pX *= PAGE_HEIGHT;
   291→   291→      pY *= PAGE_HEIGHT;
   292→   292→    }
   293→   293→  }
   294→   294→
   295→   295→  // Legacy fallback
   296→   296→  if ('wheelDelta' in event) {
   297→   297→    const wd = (event as any).wheelDelta;
   298→   298→    if ('wheelDeltaY' in event) {
   299→   299→      sY = -(event as any).wheelDeltaY / 120;
   300→   300→      sX = -(event as any).wheelDeltaX / 120;
   301→   301→    } else {
   302→   302→      sY = -wd / 120;
   303→   303→    }
   304→   304→  }
   305→   305→
   306→   306→  // Calculate spin from pixel if not set
   307→   307→  if (!sX && pX) sX = pX < 0 ? -1 : pX > 0 ? 1 : 0;
   308→   308→  if (!sY && pY) sY = pY < 0 ? -1 : pY > 0 ? 1 : 0;
   309→   309→
   310→   310→  return { spinX: sX, spinY: sY, pixelX: pX, pixelY: pY };
   311→   311→}
   312→   312→```
   313→   313→
   314→   314→### 4.4 Trackpad vs Mouse Detection
   315→   315→
   316→   316→Trackpads produce many small events rapidly; mice produce fewer large events:
   317→   317→
   318→   318→```typescript
   319→   319→let lastWheelTime = 0;
   320→   320→let wheelEventCount = 0;
   321→   321→
   322→   322→function detectInputType(event: WheelEvent): 'trackpad' | 'mouse' {
   323→   323→  const now = performance.now();
   324→   324→  const timeDelta = now - lastWheelTime;
   325→   325→
   326→   326→  if (timeDelta < 50) {
   327→   327→    wheelEventCount++;
   328→   328→  } else {
   329→   329→    wheelEventCount = 1;
   330→   330→  }
   331→   331→
   332→   332→  lastWheelTime = now;
   333→   333→
   334→   334→  // Trackpads fire many events rapidly (<20ms apart)
   335→   335→  // Mice fire discrete events with gaps
   336→   336→  if (wheelEventCount > 3 && timeDelta < 20) {
   337→   337→    return 'trackpad';
   338→   338→  }
   339→   339→
   340→   340→  // Also check delta magnitude
   341→   341→  if (Math.abs(event.deltaY) < 10 && event.deltaMode === 0) {
   342→   342→    return 'trackpad'; // Small pixel deltas = trackpad
   343→   343→  }
   344→   344→
   345→   345→  return 'mouse';
   346→   346→}
   347→   347→```
