   350→   350→
   351→   351→## 5. Momentum/Inertia Physics
   352→   352→
   353→   353→### 5.1 Basic Momentum Implementation
   354→   354→
   355→   355→```typescript
   356→   356→interface MomentumState {
   357→   357→  velocityX: number;
   358→   358→  velocityY: number;
   359→   359→  friction: number;
   360→   360→  minVelocity: number;
   361→   361→  animationId: number | null;
   362→   362→}
   363→   363→
   364→   364→const momentum: MomentumState = {
   365→   365→  velocityX: 0,
   366→   366→  velocityY: 0,
   367→   367→  friction: 0.95,      // Per-frame velocity multiplier
   368→   368→  minVelocity: 0.1,    // Stop threshold
   369→   369→  animationId: null
   370→   370→};
   371→   371→
   372→   372→function startMomentum(vx: number, vy: number) {
   373→   373→  momentum.velocityX = vx;
   374→   374→  momentum.velocityY = vy;
   375→   375→
   376→   376→  if (momentum.animationId) {
   377→   377→    cancelAnimationFrame(momentum.animationId);
   378→   378→  }
   379→   379→
   380→   380→  momentum.animationId = requestAnimationFrame(animateMomentum);
   381→   381→}
   382→   382→
   383→   383→function animateMomentum() {
   384→   384→  // Apply velocity to pan position
   385→   385→  panX += momentum.velocityX;
   386→   386→  panY += momentum.velocityY;
   387→   387→
   388→   388→  // Apply friction
   389→   389→  momentum.velocityX *= momentum.friction;
   390→   390→  momentum.velocityY *= momentum.friction;
   391→   391→
   392→   392→  // Stop when velocity is negligible
   393→   393→  const speed = Math.sqrt(
   394→   394→    momentum.velocityX ** 2 + momentum.velocityY ** 2
   395→   395→  );
   396→   396→
   397→   397→  if (speed > momentum.minVelocity) {
   398→   398→    momentum.animationId = requestAnimationFrame(animateMomentum);
   399→   399→  } else {
   400→   400→    momentum.animationId = null;
   401→   401→  }
   402→   402→}
   403→   403→
   404→   404→function stopMomentum() {
   405→   405→  if (momentum.animationId) {
   406→   406→    cancelAnimationFrame(momentum.animationId);
   407→   407→    momentum.animationId = null;
   408→   408→  }
   409→   409→  momentum.velocityX = 0;
   410→   410→  momentum.velocityY = 0;
   411→   411→}
   412→   412→```
   413→   413→
   414→   414→### 5.2 Easing Functions
   415→   415→
   416→   416→```typescript
   417→   417→// Common easing functions for zoom animations
   418→   418→const Easing = {
   419→   419→  // Quadratic ease out (Google Maps style)
   420→   420→  quadOut: (t: number) => t * (2 - t),
   421→   421→
   422→   422→  // Cubic ease out (smoother)
   423→   423→  cubicOut: (t: number) => 1 - Math.pow(1 - t, 3),
   424→   424→
   425→   425→  // Expo ease out (fast start, slow end)
   426→   426→  expoOut: (t: number) => t === 1 ? 1 : 1 - Math.pow(2, -10 * t),
   427→   427→
   428→   428→  // Circ ease out (natural feel)
   429→   429→  circOut: (t: number) => Math.sqrt(1 - Math.pow(t - 1, 2))
   430→   430→};
   431→   431→
   432→   432→function animateZoom(
   433→   433→  fromZoom: number,
   434→   434→  toZoom: number,
   435→   435→  duration: number,
   436→   436→  easing = Easing.quadOut
   437→   437→) {
   438→   438→  const startTime = performance.now();
   439→   439→
   440→   440→  function tick(currentTime: number) {
   441→   441→    const elapsed = currentTime - startTime;
   442→   442→    const progress = Math.min(elapsed / duration, 1);
   443→   443→    const easedProgress = easing(progress);
   444→   444→
   445→   445→    const currentZoom = fromZoom + (toZoom - fromZoom) * easedProgress;
   446→   446→    setZoom(currentZoom);
   447→   447→
   448→   448→    if (progress < 1) {
   449→   449→      requestAnimationFrame(tick);
   450→   450→    }
   451→   451→  }
   452→   452→
   453→   453→  requestAnimationFrame(tick);
   454→   454→}
   455→   455→```
   456→   456→
   457→   457→### 5.3 Recommended Durations
   458→   458→
   459→   459→| Animation | Duration | Easing |
   460→   460→|-----------|----------|--------|
   461→   461→| Zoom step (+/-) | 200-300ms | quadOut |
   462→   462→| Double-click zoom | 300-400ms | cubicOut |
   463→   463→| Reset view | 400-500ms | expoOut |
   464→   464→| Pan deceleration | Physics-based | Friction 0.92-0.95 |
   465→   465→
