```

### Execution Layer (HTML Overlay)

```typescript
// React components rendered as absolute positioned cards
const ExecutionOverlay: React.FC = ({
  tasks, trains, cameraX, cameraY, zoom, width, height, opacity
}) => {
  // Filter tasks for visible range
  const visibleTasks = useMemo(() => {
    const startTrain = Math.floor(cameraY);
    const endTrain = Math.ceil(cameraY + height / ROW_HEIGHT);
