| **Tactical** | 0.3x - 1.0x | Monthly bars | Stacked bars | 20px x 16px |
| **Operational** | 1.0x - 3.0x | DNA Gantt | Task blocks | 8px/day x 28px |
| **Execution** | > 3.0x | Detailed cards | HTML overlays | Variable |

### Threshold-Based LOD Switching

```typescript
const LOD_THRESHOLDS = {
  strategic: { max: 0.3 },
  tactical: { min: 0.3, max: 1.0 },
  operational: { min: 1.0, max: 3.0 },
  execution: { min: 3.0 },
};

function getLODLevel(zoom: number): LODLevel {
  if (zoom < LOD_THRESHOLDS.strategic.max) return 'strategic';
  if (zoom < LOD_THRESHOLDS.tactical.max) return 'tactical';
  if (zoom < LOD_THRESHOLDS.operational.max) return 'operational';
  return 'execution';
}
```

### Crossfade Transition Algorithm

The implementation uses smooth Hermite interpolation to avoid jarring "pop-in":

```typescript
const CROSSFADE_RANGE = 0.15; // Zoom units

function calculateLayerOpacities(zoom: number): LayerOpacities {
  // Smooth step function for crossfade
  const smoothStep = (value: number, edge0: number, edge1: number): number => {
    const t = Math.max(0, Math.min(1, (value - edge0) / (edge1 - edge0)));
    return t * t * (3 - 2 * t); // Hermite interpolation
  };

  // Calculate fade factors for each threshold
  const fadeStrategicToTactical = smoothStep(
    zoom,
    strategic - CROSSFADE_RANGE,
    strategic + CROSSFADE_RANGE
  );
  // ... similar for other transitions

  return {
    strategic: 1 - fadeStrategicToTactical,
    tactical: fadeStrategicToTactical * (1 - fadeTacticalToOperational),
    operational: fadeTacticalToOperational * (1 - fadeOperationalToExecution),
    execution: fadeOperationalToExecution,
  };
}
```

**Result**: At zoom 0.45, MACRO is 100%. At 0.50, both MACRO and MESO are 50%. At 0.55, MESO is 100%.

